import{_ as t,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"자주 묻는 질문: OAuth 인증 및 모델 문제 해결 | Antigravity Auth","description":"Antigravity Auth 플러그인의 자주 묻는 질문과 해결 방법을 알아보세요. OAuth 인증 실패 해결, 모델을 찾을 수 없음 오류 처리, 플러그인 호환성 구성 등 실용적인 가이드를 제공하여 사용 중 발생하는 다양한 문제를 신속하게 파악하고 해결할 수 있도록 도와드립니다.","frontmatter":{"title":"자주 묻는 질문: OAuth 인증 및 모델 문제 해결 | Antigravity Auth","sidebarTitle":"인증 실패 시 대처 방법","subtitle":"자주 묻는 질문: OAuth 인증 및 모델 문제 해결","description":"Antigravity Auth 플러그인의 자주 묻는 질문과 해결 방법을 알아보세요. OAuth 인증 실패 해결, 모델을 찾을 수 없음 오류 처리, 플러그인 호환성 구성 등 실용적인 가이드를 제공하여 사용 중 발생하는 다양한 문제를 신속하게 파악하고 해결할 수 있도록 도와드립니다.","order":4},"headers":[],"relativePath":"ko/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"ko/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),l={name:"ko/NoeFabris/opencode-antigravity-auth/faq/index.md"};function r(n,a,d,h,u,s){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h1><p>본 섹션에서는 Antigravity Auth 플러그인 사용 시 가장 흔히 발생하는 문제와 해결 방법을 수록했습니다. OAuth 인증 실패, 모델 요청 오류, 플러그인 호환성 문제 등 어떤 문제든 여기에서 해당하는 해결 가이드를 찾을 수 있습니다.</p><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작하기 전에 확인하세요</p><ul><li>✅ <a href="./../start/quick-install/">빠른 설치</a>를 완료하고 계정을 성공적으로 추가했는지</li><li>✅ <a href="./../start/first-auth-login/">첫 인증</a>을 완료하고 OAuth 흐름을 이해했는지</li></ul></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><p>발생한 문제 유형에 따라 해당하는 해결 가이드를 선택하세요:</p><h3 id="_1-oauth-인증-실패-해결" tabindex="-1">1. <a href="./common-auth-issues/">OAuth 인증 실패 해결</a> <a class="header-anchor" href="#_1-oauth-인증-실패-해결" aria-label="Permalink to &quot;1. [OAuth 인증 실패 해결](./common-auth-issues/)&quot;">​</a></h3><p>OAuth 인증, 토큰 갱신 및 계정 관련 일반적인 문제를 해결합니다.</p><ul><li>브라우저 인증은 성공했지만 터미널에 &quot;인증 실패&quot; 메시지가 표시됨</li><li>갑자기 &quot;Permission Denied&quot; 또는 &quot;invalid_grant&quot; 오류 발생</li><li>Safari 브라우저에서 OAuth 콜백 실패</li><li>WSL2/Docker 환경에서 인증을 완료할 수 없음</li></ul><h3 id="_2-계정-마이그레이션" tabindex="-1">2. <a href="./migration-guide/">계정 마이그레이션</a> <a class="header-anchor" href="#_2-계정-마이그레이션" aria-label="Permalink to &quot;2. [계정 마이그레이션](./migration-guide/)&quot;">​</a></h3><p>다른 머신 간 계정을 마이그레이션하고 버전 업그레이드를 처리합니다.</p><ul><li>계정을 이전 컴퓨터에서 새 컴퓨터로 마이그레이션</li><li>저장 형식의 버전 변경 이해 (v1/v2/v3)</li><li>마이그레이션 후 invalid_grant 오류 해결</li></ul><h3 id="_3-모델을-찾을-수-없음-해결" tabindex="-1">3. <a href="./model-not-found/">모델을 찾을 수 없음 해결</a> <a class="header-anchor" href="#_3-모델을-찾을-수-없음-해결" aria-label="Permalink to &quot;3. [모델을 찾을 수 없음 해결](./model-not-found/)&quot;">​</a></h3><p>모델을 찾을 수 없음, 400 오류 등 모델 관련 문제를 해결합니다.</p><ul><li><code>Model not found</code> 오류 해결</li><li><code>Invalid JSON payload received. Unknown name &quot;parameters&quot;</code> 400 오류</li><li>MCP 서버 호출 오류</li></ul><h3 id="_4-플러그인-호환성" tabindex="-1">4. <a href="./plugin-compatibility/">플러그인 호환성</a> <a class="header-anchor" href="#_4-플러그인-호환성" aria-label="Permalink to &quot;4. [플러그인 호환성](./plugin-compatibility/)&quot;">​</a></h3><p>oh-my-opencode, DCP 등의 플러그인과의 호환성 문제를 해결합니다.</p><ul><li>플러그인 로드 순서 올바르게 구성</li><li>oh-my-opencode에서 충돌하는 인증 방식 비활성화</li><li>병렬 에이전트 시나리오를 위해 PID 오프셋 활성화</li></ul><h3 id="_5-tos-경고" tabindex="-1">5. <a href="./tos-warning/">ToS 경고</a> <a class="header-anchor" href="#_5-tos-경고" aria-label="Permalink to &quot;5. [ToS 경고](./tos-warning/)&quot;">​</a></h3><p>사용 위험을 이해하고 계정 정지를 방지합니다.</p><ul><li>Google 서비스 약관 제한 이해</li><li>고위험 시나리오 식별 (신규 계정, 집중적 요청)</li><li>계정 정지를 방지하는 모범 사례 숙지</li></ul><h2 id="문제-신속-파악" tabindex="-1">문제 신속 파악 <a class="header-anchor" href="#문제-신속-파악" aria-label="Permalink to &quot;문제 신속 파악&quot;">​</a></h2><table tabindex="0"><thead><tr><th>오류 현상</th><th>권장 읽기</th></tr></thead><tbody><tr><td>인증 실패, 인증 시간 초과</td><td><a href="./common-auth-issues/">OAuth 인증 실패 해결</a></td></tr><tr><td>invalid_grant, Permission Denied</td><td><a href="./common-auth-issues/">OAuth 인증 실패 해결</a></td></tr><tr><td>Model not found, 400 오류</td><td><a href="./model-not-found/">모델을 찾을 수 없음 해결</a></td></tr><tr><td>다른 플러그인과 충돌</td><td><a href="./plugin-compatibility/">플러그인 호환성</a></td></tr><tr><td>새 컴퓨터로 변경, 버전 업그레이드</td><td><a href="./migration-guide/">계정 마이그레이션</a></td></tr><tr><td>계정 보안 우려</td><td><a href="./tos-warning/">ToS 경고</a></td></tr></tbody></table><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>문제를 해결한 후 다음을 수행할 수 있습니다:</p><ul><li>📖 <a href="./../advanced/">고급 기능</a>을 읽어 다중 계정, 세션 복구 등의 기능을 깊이 있게 이해하세요</li><li>📚 <a href="./../appendix/">부록</a>을 참조하여 아키텍처 설계와 전체 구성 참조를 확인하세요</li><li>🔄 <a href="./../changelog/">변경 로그</a>를 팔로우하여 최신 기능과 변경 사항을 받아보세요</li></ul>',26)])])}const f=t(l,[["render",r]]);export{p as __pageData,f as default};
